package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.BedragMetCarryOver;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoonFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_BEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_GEBOORTEBEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_QUARANTAINEBEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;

@AllArgsConstructor
public class PrestatiesGewoneBezoldiging {

    private static final int SCALE = 2;
    private static final LocalDate START_LOONCODE_170_BIJ_WACHTGELD = new LocalDate(2025, 1, 1);

    private final ConstantManager constantManager;
    private final LoonElementVerwerker loonElementVerwerker;
    private final Disponibiliteit disponibiliteit;

    public void verwerk(
            LoonElementManager manager, LoonCodeManager loonCodeManager, RekenTijd rekenTijd,
            AardKodeExtensie looncodeGewoonLoon, PrestatieSamenvatting samenvatting, BigDecimal prestatieNoemer, Opper opper,
            MoneyMap<AardKodeExtensie> carryoverMap) {
        Money svBrutoBedrag = Money.ZERO;
        Money svBasisRsz = Money.ZERO;

        Money bedragWachtGeld = Money.ZERO;
        Money basisRszWachtGeld = Money.ZERO;
        Money carryOverWachtgeld = Money.ZERO;

        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        for (LoonElement element : loonElementen) {
            AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
            Money basisBedrag = element.getPropertyMoney(BASIS_BEDRAG_KEY);
            BedragMetCarryOver bedragMetCarryOver = new BedragMetCarryOver(basisBedrag, carryoverMap.getMoney(aardKodeExtensie));
            BedragMetCarryOver bedragWachtGeldMetCarryOver = new BedragMetCarryOver(Money.ZERO, carryOverWachtgeld);
            if (!aardKodeExtensie.isForfaitair()) {
                BigDecimal tellerGewoonLoon = samenvatting.getTellerGewoneBezoldiging();
                if (aardKodeExtensie.isGewaarborgdLoon() || aardKodeExtensie.isGewaarborgdLoon100()) {
                    tellerGewoonLoon = tellerGewoonLoon.add(samenvatting.getTellerZiekteEersteWeek());
                }
                bedragMetCarryOver.berekenBedragMetCarryOver(berekenBedragVoorTeller(basisBedrag, tellerGewoonLoon, prestatieNoemer));
                berekenBedragDisponibiliteitGeenWachtGeld(rekenTijd, samenvatting, prestatieNoemer, opper, aardKodeExtensie, looncodeGewoonLoon, basisBedrag,
                        bedragMetCarryOver);
                berekenBedragVoorTeller80En82(rekenTijd, looncodeGewoonLoon, samenvatting, prestatieNoemer, element, aardKodeExtensie, basisBedrag, bedragMetCarryOver,
                        bedragWachtGeldMetCarryOver);
                carryoverMap.put(aardKodeExtensie, bedragMetCarryOver.getCarryover());
                carryOverWachtgeld = bedragWachtGeldMetCarryOver.getCarryover();
            }
            Money basisRsz = bedragMetCarryOver.getBedrag();
            Money basisRszWachtGeldElement = bedragWachtGeldMetCarryOver.getCarryover();
            if (BrutoTools.heeftFactorBassi_1_25(opper, rekenTijd)) {
                basisRsz = basisRsz.multiply(BrutoTools.FACTOR_BASSI_1_25).round(SCALE);
                basisRszWachtGeldElement = basisRszWachtGeldElement.multiply(BrutoTools.FACTOR_BASSI_1_25).round(SCALE);
            }
            basisRsz = loonElementVerwerker.verhogingBassi(basisRsz, opper, rekenTijd);
            basisRszWachtGeldElement = loonElementVerwerker.verhogingBassi(basisRszWachtGeldElement, opper, rekenTijd);

            bedragWachtGeld = bedragWachtGeld.add(bedragWachtGeldMetCarryOver.getBedrag());
            basisRszWachtGeld = basisRszWachtGeld.add(basisRszWachtGeldElement);

            if (heeftDispoOntstentenis(opper, rekenTijd)) {
                bedragWachtGeld = bedragWachtGeld.add(bedragMetCarryOver.getBedrag());
                basisRszWachtGeld = basisRszWachtGeld.add(basisRsz);
                bedragMetCarryOver = new BedragMetCarryOver(Money.ZERO, bedragMetCarryOver.getCarryover());
                basisRsz = Money.ZERO;
            }


            Money salarisVerhoging = opper.getBasisJaarWedde().getSalarisVerhoging();
            if (looncodeGewoonLoon.equals(aardKodeExtensie) && salarisVerhoging.signum() != 0) {
                Money brutoTotaal = bedragMetCarryOver.getBedrag();
                Money basisRszTotaal = basisRsz;
                Money jaarwedde = opper.getBasisJaarWedde().getJaarWedde();
                Money jaarweddeTotaal = jaarwedde.add(salarisVerhoging);

                svBrutoBedrag = brutoTotaal.multiply(salarisVerhoging.divide(jaarweddeTotaal)).round(SCALE);
                svBasisRsz = basisRszTotaal.multiply(salarisVerhoging.divide(jaarweddeTotaal)).round(SCALE);

                bedragMetCarryOver.trekBedragAf(svBrutoBedrag);
                basisRsz = basisRszTotaal.subtract(svBasisRsz);

            }

            element.putProperty(BRUTO_MAANDLOON_KEY, bedragMetCarryOver.getBedrag());
            if (BrutoTools.heeftBassi(aardKodeExtensie, opper.getOpdracht().getHoedanigheid())) {
                element.putProperty(BASIS_SOCIALE_INHOUDINGEN_KEY, basisRsz);
            }

        }
        Money salarisVerhoging = opper.getBasisJaarWedde().getSalarisVerhoging();
        if (salarisVerhoging.signum() != 0) {
            GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
            AardKodeExtensie looncodeSalarisVerhoging = gewoonLoon.createGegarandeerdeSalarisverhoging();
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeSalarisVerhoging, svBrutoBedrag, svBasisRsz, rekenTijd, carryoverMap);
        }

        if (bedragWachtGeld.signum() != 0) {
            GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
            AardKodeExtensie looncodeWachtgeldAmbtsontheffing = gewoonLoon.createWachtgeldAmbtsontheffing();
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeWachtgeldAmbtsontheffing, bedragWachtGeld, basisRszWachtGeld, rekenTijd, carryoverMap);
        }
    }

    private boolean heeftDispoOntstentenis(Opper opper, RekenTijd rekenTijd) {
        return !rekenTijd.beginDatum.isBefore(START_LOONCODE_170_BIJ_WACHTGELD) && opper.getAfwezighedenInvoerModule() != null &&
                opper.getAfwezighedenInvoerModule().stream()
                        .anyMatch(x -> LoonCodeTools.isWachtgeldAmbtsontheffing(x.getAardKodeExtensie()));
    }

    private void berekenBedragDisponibiliteitGeenWachtGeld(
            RekenTijd rekenTijd, PrestatieSamenvatting samenvatting, BigDecimal prestatieNoemer, Opper opper, AardKodeExtensie aardKodeExtensie,
            AardKodeExtensie looncodeGewoonLoon,
            Money basisBedrag, BedragMetCarryOver bedragMetCarryOver) {
        if (!aardKodeExtensie.getOmzettenWachtweddeDispo()) {
            DispoType dispoType = disponibiliteit.bepaalDispoType(aardKodeExtensie, looncodeGewoonLoon, opper, rekenTijd);
            if (dispoType == DispoType.DISPO_100) {
                bedragMetCarryOver.voegBedragToe(berekenBedragVoorTeller(basisBedrag, samenvatting.getTellerDisponibiliteit(), prestatieNoemer));
            } else if (dispoType == DispoType.DISPO_60) {
                BigDecimal percentageDispo60 = disponibiliteit.bepaalPercentage60(opper, rekenTijd);
                BigDecimal tellerDisponibiliteit = samenvatting.getTellerDisponibiliteit100().add(samenvatting.getTellerDisponibiliteit60().multiply(percentageDispo60));
                bedragMetCarryOver.voegBedragToe(berekenBedragVoorTeller(basisBedrag, tellerDisponibiliteit, prestatieNoemer));
            } else {
                // do nothing
            }
        }
    }

    private void berekenBedragVoorTeller80En82(
            RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, PrestatieSamenvatting samenvatting, BigDecimal prestatieNoemer, LoonElement element,
            AardKodeExtensie aardKodeExtensie, Money basisBedrag, BedragMetCarryOver bedragMetCarryOver, BedragMetCarryOver bedragWachtgeldMetCarryOver) {
        BigDecimal percentage80 = bepaalPercentageVoorTeller80En82(rekenTijd, looncodeGewoonLoon, aardKodeExtensie, Konstanten.KST_PCT_80);
        berekenBedragVoorTeller80(samenvatting, prestatieNoemer, element, basisBedrag, bedragMetCarryOver, percentage80);

        Money bedragOvermacht = berekenBedragVoorTellerOvermacht(samenvatting, prestatieNoemer, element, basisBedrag, bedragMetCarryOver, percentage80);
        if (rekenTijd.beginDatum.isBefore(START_LOONCODE_170_BIJ_WACHTGELD)) {
            bedragMetCarryOver.voegBedragToe(bedragOvermacht);
        } else {
            bedragWachtgeldMetCarryOver.voegBedragToe(bedragOvermacht);
        }

        BigDecimal percentage82 = bepaalPercentageVoorTeller80En82(rekenTijd, looncodeGewoonLoon, aardKodeExtensie, Konstanten.KST_PCT_82);
        berekenBedragVoorTellers82(samenvatting, prestatieNoemer, element, basisBedrag, bedragMetCarryOver, percentage82);
    }

    private void berekenBedragVoorTeller80(
            PrestatieSamenvatting samenvatting, BigDecimal noemer, LoonElement element, Money basisBedrag, BedragMetCarryOver bedragMetCarryOver, BigDecimal percentage) {
        Money bedrag = element.containsProperty(BASIS_QUARANTAINEBEDRAG_KEY) ? element.getPropertyMoney(BASIS_QUARANTAINEBEDRAG_KEY) : basisBedrag;
        bedragMetCarryOver.voegBedragToe(berekenBrutoBedragVoorTellerMetPercentage(bedrag, samenvatting.getTellerBetaling80(), noemer, percentage));
    }

    private Money berekenBedragVoorTellerOvermacht(
            PrestatieSamenvatting samenvatting, BigDecimal noemer, LoonElement element, Money basisBedrag, BedragMetCarryOver bedragMetCarryOver, BigDecimal percentage) {
        Money bedrag = element.containsProperty(BASIS_GEBOORTEBEDRAG_KEY) ? element.getPropertyMoney(BASIS_GEBOORTEBEDRAG_KEY) : basisBedrag;
        return berekenBrutoBedragVoorTellerMetPercentage(bedrag, samenvatting.getTellerBetalingOvermacht(), noemer, percentage);
    }

    private void berekenBedragVoorTellers82(
            PrestatieSamenvatting samenvatting, BigDecimal noemer, LoonElement element, Money basisBedrag, BedragMetCarryOver bedragMetCarryOver, BigDecimal percentage) {
        bedragMetCarryOver.voegBedragToe(berekenBrutoBedragVoorTellerMetPercentage(basisBedrag, samenvatting.getTellerBetaling82(), noemer, percentage));

        Money bedrag = element.containsProperty(BASIS_GEBOORTEBEDRAG_KEY) ? element.getPropertyMoney(BASIS_GEBOORTEBEDRAG_KEY) : basisBedrag;
        bedragMetCarryOver.voegBedragToe(berekenBrutoBedragVoorTellerMetPercentage(bedrag, samenvatting.getTellerGeboorteVerlof(), noemer, percentage));
    }

    private BigDecimal bepaalPercentageVoorTeller80En82(RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, AardKodeExtensie aardKodeExtensie, Konstanten kstPct) {
        BigDecimal percentage;
        if (aardKodeExtensie.behoortTotGroep(LooncodeGroepKeyStrings.KEDSPECIAALTYPE_HASTA_KEY) || looncodeGewoonLoon.equals(aardKodeExtensie)) {
            percentage = constantManager.getActualConstant(kstPct, rekenTijd).getProcentFactor();
        } else {
            percentage = BigDecimal.ONE;
        }
        return percentage;
    }

    private Money berekenBedragVoorTeller(Money bedrag, BigDecimal teller, BigDecimal noemer) {
        return bedrag.multiply(teller).divide(noemer);
    }

    private Money berekenBrutoBedragVoorTellerMetPercentage(Money bedrag, BigDecimal teller, BigDecimal noemer, BigDecimal percentage) {
        return berekenBedragVoorTeller(bedrag, teller, noemer)
                .multiply(percentage);
    }
}
